11	// RunnerDockerImage is the container image used for docker-mode runners.
12	const RunnerDockerImage = "ghcr.io/actions/actions-runner:latest"
13	
14	// dockerRunnerEntryScript returns the entry script for the container. preSetup is a bash script
15	// that runs inside the container before the runner starts; use it to install tools needed by
16	// workflows (e.g., Node.js for awf). Official ghcr.io/actions/actions-runner has no CMD; it
17	// expects config.sh then run.sh.
18	func dockerRunnerEntryScript(preSetup string) string {
19		setup := `cd /home/runner && if [ ! -f .runner ]; then ./config.sh --unattended --replace; fi && exec ./run.sh`
20		if preSetup != "" {
21			return preSetup + " && " + setup
22		}
23		return setup
24	}
