26	// ContainerName returns the Docker container name for a runner instance.
27	func ContainerName(instanceName string) string {
28		return "gh-runner-" + instanceName
29	}
30	
31	func containerName(instanceName string) string {
32		return ContainerName(instanceName)
33	}
