35	// shellSingleQuote wraps s in single quotes for a POSIX shell word (safe for docker -e on Linux/macOS SSH).
36	func shellSingleQuote(s string) string {
37		return "'" + strings.ReplaceAll(s, "'", "'\\''") + "'"
38	}
39	
40	// dockerEnvFlag renders one -e flag as a single shell word: -e 'NAME=value'
41	func dockerEnvFlag(name, value string) string {
42		return "-e " + shellSingleQuote(name+"="+value)
43	}
44	
45	// dockerCapAddFlags renders zero or more --cap-add flags for docker run (Linux capability names, e.g. NET_ADMIN).
46	func dockerCapAddFlags(capAdds []string) string {
47		if len(capAdds) == 0 {
48			return ""
49		}
50		var b strings.Builder
51		for _, c := range capAdds {
52			c = strings.TrimSpace(c)
53			if c == "" {
54				continue
55			}
56			fmt.Fprintf(&b, "--cap-add %s ", c)
57		}
58		return b.String()
59	}
