61	type dockerStartOpts struct {
62		ContainerName string
63		InstanceName  string
64		RegToken      string
65		RepoURL       string
66		Labels        string
67		SockMount     string
68		Image         string
69		NetworkMode   string
70		CapAdds       []string
71		RunnerGroup   string
72		Ephemeral     bool
73		PreSetup      string
74	}
75	
76	func dockerStartCommand(opts dockerStartOpts) string {
77		var b strings.Builder
78		fmt.Fprintf(&b, "docker run -d --name %s ", opts.ContainerName)
79		if strings.TrimSpace(opts.NetworkMode) == "host" {
80			b.WriteString("--network host ")
81		}
82		restartPolicy := "unless-stopped"
83		if opts.Ephemeral {
84			restartPolicy = "no"
85		}
86		fmt.Fprintf(&b, "--restart %s ", restartPolicy)
87		b.WriteString(dockerCapAddFlags(opts.CapAdds))
88		b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_URL", opts.RepoURL))
89		b.WriteByte(' ')
90		b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_TOKEN", opts.RegToken))
91		b.WriteByte(' ')
92		b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_NAME", opts.InstanceName))
93		b.WriteByte(' ')
94		b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_LABELS", opts.Labels))
95		b.WriteByte(' ')
96		b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_WORK", "_work"))
97		b.WriteByte(' ')
98		if opts.RunnerGroup != "" {
99			b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_RUNNERGROUP", opts.RunnerGroup))
100			b.WriteByte(' ')
101		}
102		if opts.Ephemeral {
103			b.WriteString(dockerEnvFlag("ACTIONS_RUNNER_INPUT_EPHEMERAL", "true"))
104			b.WriteByte(' ')
105		}
106		if s := strings.TrimSpace(opts.SockMount); s != "" {
107			b.WriteString(s)
108			b.WriteByte(' ')
109		}
110		b.WriteString("--entrypoint /bin/bash ")
111		b.WriteString(opts.Image)
112		b.WriteString(" -c ")
113		b.WriteString(shellSingleQuote(dockerRunnerEntryScript(opts.PreSetup)))
114		return b.String()
115	}
