117	// DefaultDockerSocket is the conventional Docker daemon socket path on Linux and macOS hosts.
118	const DefaultDockerSocket = "/var/run/docker.sock"
119	
120	// defaultDockerSocket is an unexported alias kept for internal use within this package.
121	const defaultDockerSocket = DefaultDockerSocket
122	
123	// socketPathFromDockerContextHost returns the filesystem path when endpoint is a unix:// Docker API URL.
124	func socketPathFromDockerContextHost(endpoint string) (path string, ok bool) {
125		endpoint = strings.TrimSpace(endpoint)
126		if endpoint == "" {
127			return "", false
128		}
129		if !strings.HasPrefix(endpoint, "unix://") {
130			return "", false
131		}
132		path = strings.TrimPrefix(endpoint, "unix://")
133		if path == "" || path[0] != '/' {
134			return "", false
135		}
136		return path, true
137	}
138	
139	func remoteDockerSocketOK(h *host.Host, path string) (bool, error) {
140		q := shellSingleQuote(path)
141		out, err := h.Run(fmt.Sprintf("test -S %s && echo ok || echo missing", q))
142		if err != nil {
143			return false, err
144		}
145		return strings.TrimSpace(out) == "ok", nil
146	}
147	
148	// EffectiveDockerSocket returns the host-side Docker socket path for bind-mounting on Linux and macOS.
149	// When HostConfig.DockerSocket is set, that path is used if it exists. Otherwise gh sr probes, in order:
150	// /var/run/docker.sock, the active docker context unix endpoint (Colima, rootless Docker, etc.),
151	// and on macOS ~/.colima/default/docker.sock.
152	func EffectiveDockerSocket(h *host.Host) (string, error) {
153		if h.OS != "linux" && h.OS != "darwin" {
154			return "", fmt.Errorf("EffectiveDockerSocket: unsupported OS %q", h.OS)
155		}
156		if p := strings.TrimSpace(h.DockerSocket); p != "" {
157			ok, err := remoteDockerSocketOK(h, p)
158			if err != nil {
159				return "", fmt.Errorf("checking docker_socket on host %s: %w", h.Name, err)
160			}
161			if !ok {
162				return "", fmt.Errorf("docker_socket not found or not a socket at %s on host %s", p, h.Name)
163			}
164			return p, nil
165		}
166		ok, err := remoteDockerSocketOK(h, defaultDockerSocket)
167		if err != nil {
168			return "", fmt.Errorf("checking Docker socket on host %s: %w", h.Name, err)
169		}
170		if ok {
171			return defaultDockerSocket, nil
172		}
173		ctxOut, derr := dockerRun(h, `docker context inspect -f '{{.Endpoints.docker.Host}}'`)
174		if derr == nil {
175			if p, parseOK := socketPathFromDockerContextHost(ctxOut); parseOK {
176				ok2, err2 := remoteDockerSocketOK(h, p)
177				if err2 != nil {
178					return "", fmt.Errorf("checking Docker socket from context on host %s: %w", h.Name, err2)
179				}
180				if ok2 {
181					return p, nil
182				}
183			}
184		}
185		if h.OS == "darwin" {
186			out, rerr := h.Run(prependDarwinDockerPATH(h, `p="$HOME/.colima/default/docker.sock"; if test -S "$p"; then printf '%s' "$p"; fi`))
187			if rerr == nil {
188				if p := strings.TrimSpace(out); p != "" {
189					return p, nil
190				}
191			}
192		}
193		hint := "ensure Docker is running (rootless Docker: gh sr uses your default docker context; set docker_socket to override)"
194		if h.OS == "darwin" {
195			hint = "ensure Docker Desktop/OrbStack/Colima is running, or set docker_socket for a non-default socket path"
196		}
197		return "", fmt.Errorf("no usable Docker socket found on host %s; %s", h.Name, hint)
198	}
