200	// dockerEngineSockFlags returns the docker run flags needed to expose the host Docker socket inside
201	// a Linux actions-runner container and grant the container's runner user access to it.
202	//
203	// It returns both a -v bind-mount and a --group-add <GID> flag. The GID is read from the host
204	// socket's owning group via `stat -c '%g'`; this avoids "permission denied" when the container's
205	// runner user (uid 1001) is not in the host docker group. If the GID cannot be determined, only
206	// the mount is returned (best-effort; caller may still get EACCES at runtime).
207	//
208	// socketPath is the host-side socket (from HostConfig.DockerSocket, defaulting to /var/run/docker.sock).
209	// The container-side path is always /var/run/docker.sock so job scripts use the default DOCKER_HOST.
210	func dockerEngineSockFlags(h *host.Host, socketPath string) string {
211		if socketPath == "" {
212			socketPath = defaultDockerSocket
213		}
214		mount := fmt.Sprintf("-v %s:/var/run/docker.sock ", socketPath)
215	
216		// Query the GID that owns the socket on the host so we can pass --group-add.
217		out, err := h.Run(fmt.Sprintf("stat -c '%%g' %s 2>/dev/null", socketPath))
218		gid := strings.TrimSpace(out)
219		if err != nil || gid == "" || gid == "0" {
220			// GID 0 means root owns it and no special group; skip --group-add (no benefit or unknown).
221			return mount
222		}
223		return mount + fmt.Sprintf("--group-add %s ", gid)
224	}
225	
226	// darwinDockerBindSourcePath returns the filesystem path to use as the host side of
227	// docker run -v …:/var/run/docker.sock on macOS. Colima exposes the API at
228	// ~/.colima/.../docker.sock on the macOS host, but bind-mounting that path fails with
229	// virtiofs (dockerd mkdir on the socket path: operation not supported; see
230	// https://github.com/abiosoft/colima/issues/997). The same daemon accepts
231	// /var/run/docker.sock (VM-local). Caller must only use this when h.OS == "darwin".
232	func darwinDockerBindSourcePath(resolvedSocket string) string {
233		if resolvedSocket == "" {
234			return resolvedSocket
235		}
236		if strings.Contains(resolvedSocket, "/.colima/") && strings.HasSuffix(resolvedSocket, "docker.sock") {
237			return defaultDockerSocket
238		}
239		return resolvedSocket
240	}
241	
242	// darwinDockerSockFlags returns the docker run flags to bind-mount the Docker socket on a macOS
243	// host. On macOS (Docker Desktop, OrbStack, Colima) the socket is accessible to all processes
244	// inside the VM — there is no docker group GID mismatch — so only the -v mount is needed.
245	//
246	// socketPath is the host-side socket (from HostConfig.DockerSocket, defaulting to /var/run/docker.sock).
247	func darwinDockerSockFlags(socketPath string) string {
248		if socketPath == "" {
249			socketPath = defaultDockerSocket
250		}
251		return fmt.Sprintf("-v %s:/var/run/docker.sock ", socketPath)
252	}
253	
254	// dockerWindowsEngineSockMount is the bind-mount for the Docker engine socket on Windows hosts
255	// (Docker Desktop Linux engine; path is resolved inside the Hyper-V/WSL2 VM).
256	const dockerWindowsEngineSockMount = "-v /var/run/docker.sock:/var/run/docker.sock "
257	
258	// DockerWindowsSockGIDProbeCommand returns the docker CLI line to read the owning GID of
259	// /var/run/docker.sock inside the Docker Desktop Linux engine. Uses sh+stat because the runner
260	// image has no one-shot default CMD suitable for stat.
261	func DockerWindowsSockGIDProbeCommand(image string) string {
262		return fmt.Sprintf(
263			`docker run --rm -v /var/run/docker.sock:/var/run/docker.sock --entrypoint sh %s -c "stat -c '%%g' /var/run/docker.sock"`,
264			image,
265		)
266	}
267	
268	// appendGroupAddForDockerSockGID appends --group-add when probe output is a non-empty numeric GID.
269	// Even GID 0 (root) is added because the docker socket is often owned by root:root on Docker Desktop,
270	// and adding GID 0 as a supplemental group grants the container's runner user access to it.
271	func appendGroupAddForDockerSockGID(mount, gidProbeOutput string) string {
272		gid := strings.TrimSpace(gidProbeOutput)
273		if gid == "" {
274			return mount
275		}
276		for _, c := range gid {
277			if c < '0' || c > '9' {
278				return mount
279			}
280		}
281		return mount + fmt.Sprintf("--group-add %s ", gid)
282	}
283	
284	// dockerEngineSockFlagsWindows returns docker run flags for the Docker socket on a Windows host
285	// running Docker Desktop (Linux containers mode). The socket lives in the Linux engine VM; we
286	// probe its group GID via a disposable container because Windows has no Unix stat on that path.
287	func dockerEngineSockFlagsWindows(h *host.Host) string {
288		out, err := dockerRun(h, DockerWindowsSockGIDProbeCommand(RunnerDockerImage)+` 2>$null`)
289		if err != nil {
290			return dockerWindowsEngineSockMount
291		}
292		return appendGroupAddForDockerSockGID(dockerWindowsEngineSockMount, out)
293	}
294	
295	// dockerEngineSockPreflightCheck verifies the socket path is present and is a socket on the host
296	// before docker run. Returns an error with an actionable message if the socket is missing.
297	func dockerEngineSockPreflightCheck(h *host.Host, socketPath string) error {
298		if socketPath == "" {
299			socketPath = defaultDockerSocket
300		}
301		out, err := h.Run(fmt.Sprintf("test -S %s && echo ok || echo missing", socketPath))
302		if err != nil {
303			return fmt.Errorf("checking Docker socket %s on host: %w", socketPath, err)
304		}
305		if strings.TrimSpace(out) != "ok" {
306			msg := fmt.Sprintf(
307				"Docker socket not found at %s on host %s; ensure Docker is installed and running (or set docker_socket in config for rootless Docker)",
308				socketPath, h.Name,
309			)
310			return fmt.Errorf("%s", msg)
311		}
312		return nil
313	}
314	
315	// prependDarwinDockerPATH prefixes a remote shell command on macOS so the Docker CLI is on PATH
316	// when SSH uses a minimal environment (missing /usr/local/bin and /opt/homebrew/bin).
317	func prependDarwinDockerPATH(h *host.Host, cmd string) string {
318		if h.OS != "darwin" {
319			return cmd
320		}
321		return `export PATH="/usr/local/bin:/opt/homebrew/bin:$PATH"; ` + cmd
322	}
323	
324	// dockerRun executes a Docker CLI command on the host, using PowerShell
325	// wrapping on Windows and raw shell on Linux/macOS.
326	func dockerRun(h *host.Host, cmd string) (string, error) {
327		if h.OS == "windows" {
328			return h.RunShell(windowsDockerCommand(cmd))
329		}
330		return h.Run(prependDarwinDockerPATH(h, cmd))
331	}
332	
333	// dockerRunIgnoreErr is like dockerRun but discards the error (for best-effort cleanup).
334	func dockerRunIgnoreErr(h *host.Host, cmd string) {
335		if h.OS == "windows" {
336			h.RunShell(windowsDockerCommand(cmd))
337		} else {
338			h.Run(prependDarwinDockerPATH(h, cmd))
339		}
340	}
