349	// windowsDockerCommand forces Docker to use an isolated config directory that
350	// avoids the Windows native credential helper in SSH sessions. The dummy auth
351	// entry keeps Docker CLI from auto-detecting wincred as the default store when
352	// no auth is configured.
353	func windowsDockerCommand(cmd string) string {
354		return strings.TrimSpace(fmt.Sprintf(`
355	$ghsrDockerConfigDir = Join-Path $env:TEMP 'gh-sr-docker-config'
356	New-Item -ItemType Directory -Force -Path $ghsrDockerConfigDir | Out-Null
357	$ghsrDockerConfigFile = Join-Path $ghsrDockerConfigDir 'config.json'
358	$ghsrDockerConfigJson = @'
359	{
360	  "auths": {
361	    "ghsr.invalid": {
362	      "auth": "Z2hyOmdocg=="
363	    }
364	  },
365	  "credsStore": ""
366	}
367	'@
368	[System.IO.File]::WriteAllText($ghsrDockerConfigFile, $ghsrDockerConfigJson, [System.Text.UTF8Encoding]::new($false))
369	$env:DOCKER_CONFIG = $ghsrDockerConfigDir
370	%s
371	`, cmd))
372	}
