374	func (m *Manager) setupDockerWindows(h *host.Host) error {
375		out, err := dockerRun(h, `docker info --format "{{.ServerVersion}}"`)
376		if err != nil || strings.TrimSpace(out) == "" {
377			return fmt.Errorf("docker not available on host %s: install Docker Desktop and ensure it is running", h.Name)
378		}
379		fmt.Fprintf(m.out(), "  %s: Docker %s available\n", h.Name, strings.TrimSpace(out))
380	
381		fmt.Fprintf(m.out(), "  %s: pulling runner image...\n", h.Name)
382		if _, err := dockerRun(h, fmt.Sprintf("docker pull %s", RunnerDockerImage)); err != nil {
383			return fmt.Errorf("pulling Docker image: %w", err)
384		}
385	
386		return nil
387	}
