389	// UnixDockerCLIInstalled reports whether a docker binary exists on PATH on the host.
390	func UnixDockerCLIInstalled(h *host.Host) (bool, error) {
391		out, err := h.Run(prependDarwinDockerPATH(h, `if command -v docker >/dev/null 2>&1; then echo yes; else echo no; fi`))
392		if err != nil {
393			return false, err
394		}
395		switch strings.TrimSpace(out) {
396		case "yes":
397			return true, nil
398		case "no":
399			return false, nil
400		default:
401			return false, fmt.Errorf("unexpected output checking docker CLI: %q", out)
402		}
403	}
404	
405	func wrapDockerInfoErr(h *host.Host, err error) error {
406		if err == nil {
407			return nil
408		}
409		lower := strings.ToLower(err.Error())
410		switch {
411		case strings.Contains(lower, "permission denied") && strings.Contains(lower, "docker.sock"):
412			userHint := "$USER"
413			if h != nil {
414				if u := h.SSHUser(); u != "" {
415					userHint = u
416				}
417			}
418			return fmt.Errorf(
419				"cannot access Docker socket (on the host as root: sudo usermod -aG docker %s; then reconnect SSH or run: newgrp docker; or use root in hosts.*.addr): %w",
420				userHint, err,
421			)
422		case strings.Contains(lower, "permission denied"):
423			return fmt.Errorf("permission denied talking to Docker: %w", err)
424		case strings.Contains(lower, "cannot connect to the docker daemon"),
425			strings.Contains(lower, "is the docker daemon running"),
426			strings.Contains(lower, "connection refused"):
427			return fmt.Errorf("Docker daemon not reachable (start the Docker service, e.g. systemctl start docker; see README): %w", err)
428		default:
429			return err
430		}
431	}
432	
433	// UnixDockerServerVersion returns the Docker Engine server version from docker info, or an error
434	// that distinguishes socket permissions and daemon reachability from other failures.
435	func UnixDockerServerVersion(h *host.Host) (string, error) {
436		out, err := h.Run(prependDarwinDockerPATH(h, "docker info --format '{{.ServerVersion}}'"))
437		out = strings.TrimSpace(out)
438		if err == nil {
439			if out == "" {
440				return "", fmt.Errorf("docker info returned empty server version")
441			}
442			return out, nil
443		}
444		return "", wrapDockerInfoErr(h, err)
445	}
