447	func (m *Manager) setupDockerUnix(h *host.Host) error {
448		hasCLI, err := UnixDockerCLIInstalled(h)
449		if err != nil {
450			return fmt.Errorf("checking docker on host %s: %w", h.Name, err)
451		}
452	
453		if hasCLI {
454			out, verr := UnixDockerServerVersion(h)
455			if verr == nil {
456				fmt.Fprintf(m.out(), "  %s: Docker %s available\n", h.Name, out)
457				fmt.Fprintf(m.out(), "  %s: pulling runner image...\n", h.Name)
458				if _, err := dockerRun(h, fmt.Sprintf("docker pull %s", RunnerDockerImage)); err != nil {
459					return fmt.Errorf("pulling Docker image: %w", err)
460				}
461				return nil
462			}
463			if h.OS == "darwin" {
464				return fmt.Errorf(
465					"docker not available on host %s: install Docker Desktop, OrbStack, or Colima and ensure the Docker CLI works in your SSH session: %w",
466					h.Name, verr,
467				)
468			}
469			return fmt.Errorf("docker on host %s is not usable: %w", h.Name, verr)
470		}
471	
472		if h.OS == "darwin" {
473			return fmt.Errorf(
474				"docker not available on host %s: install Docker Desktop, OrbStack, or Colima and ensure the Docker CLI works in your SSH session",
475				h.Name,
476			)
477		}
478	
479		fmt.Fprintf(m.out(), "  %s: Docker not found, attempting to install...\n", h.Name)
480		installCmd := linuxElevatePrelude + `
481				if ! command -v curl >/dev/null 2>&1; then
482					if command -v apt-get >/dev/null 2>&1; then $SUDO apt-get update && $SUDO apt-get install -y curl;
483					elif command -v yum >/dev/null 2>&1; then $SUDO yum install -y curl;
484					elif command -v apk >/dev/null 2>&1; then $SUDO apk add curl;
485					fi
486				fi &&
487				curl -fsSL https://get.docker.com | $SUDO sh
488			`
489		if _, instErr := h.Run(installCmd); instErr != nil {
490			return fmt.Errorf(
491				"failed to install docker on host %s (need root SSH, passwordless sudo, or install Docker manually; see gh sr doctor): %w",
492				h.Name, instErr,
493			)
494		}
495	
496		hasCLI, err = UnixDockerCLIInstalled(h)
497		if err != nil {
498			return fmt.Errorf("rechecking docker on host %s: %w", h.Name, err)
499		}
500		if !hasCLI {
501			return fmt.Errorf("docker still not installed on host %s after installation attempt", h.Name)
502		}
503		out, verr := UnixDockerServerVersion(h)
504		if verr != nil {
505			return fmt.Errorf("docker installed on host %s but still not usable (e.g. add user to 'docker' group and reconnect SSH): %w", h.Name, verr)
506		}
507		fmt.Fprintf(m.out(), "  %s: Docker %s available\n", h.Name, out)
508	
509		fmt.Fprintf(m.out(), "  %s: pulling runner image...\n", h.Name)
510		if _, err := dockerRun(h, fmt.Sprintf("docker pull %s", RunnerDockerImage)); err != nil {
511			return fmt.Errorf("pulling Docker image: %w", err)
512		}
513	
514		return nil
515	}
