517	func (m *Manager) startDocker(h *host.Host, rc config.RunnerConfig, instanceName string) error {
518		cname := containerName(instanceName)
519	
520		if h.OS == "windows" {
521			running, _ := dockerRun(h, fmt.Sprintf(`docker inspect -f "{{.State.Running}}" %s 2>$null`, cname))
522			if strings.TrimSpace(running) == "true" {
523				fmt.Fprintf(m.out(), "  %s: already running\n", instanceName)
524				return nil
525			}
526			dockerRunIgnoreErr(h, fmt.Sprintf("docker rm -f %s 2>$null", cname))
527		} else {
528			running, _ := dockerRun(h, fmt.Sprintf("docker inspect -f '{{.State.Running}}' %s 2>/dev/null", cname))
529			if strings.TrimSpace(running) == "true" {
530				fmt.Fprintf(m.out(), "  %s: already running\n", instanceName)
531				return nil
532			}
533			dockerRunIgnoreErr(h, fmt.Sprintf("docker rm -f %s 2>/dev/null || true", cname))
534		}
535	
536		// Auto-pull image if not present locally.
537		imgCheck := fmt.Sprintf("docker images -q %s", RunnerDockerImage)
538		if h.OS == "windows" {
539			imgCheck += " 2>$null"
540		} else {
541			imgCheck += " 2>/dev/null"
542		}
543		imgOut, _ := dockerRun(h, imgCheck)
544		if strings.TrimSpace(imgOut) == "" {
545			fmt.Fprintf(m.out(), "  %s: pulling runner image...\n", instanceName)
546			if _, pullErr := dockerRun(h, fmt.Sprintf("docker pull %s", RunnerDockerImage)); pullErr != nil {
547				return fmt.Errorf("pulling Docker image for %s: %w", instanceName, pullErr)
548			}
549		}
550	
551		regToken, err := m.GitHub.GetRegistrationTokenScoped(rc.Scope(), rc.ScopeTarget())
552		if err != nil {
553			return err
554		}
555	
556		labels := strings.Join(rc.EffectiveLabels(h.OS, h.Arch), ",")
557		var repoURL string
558		if rc.Org != "" {
559			repoURL = fmt.Sprintf("https://github.com/%s", rc.Org)
560		} else {
561			repoURL = fmt.Sprintf("https://github.com/%s", rc.Repo)
562		}
563	
564		var sockFlags string
565		switch h.OS {
566		case "linux", "darwin":
567			sockPath, err := EffectiveDockerSocket(h)
568			if err != nil {
569				return err
570			}
571			if h.OS == "linux" {
572				sockFlags = dockerEngineSockFlags(h, sockPath)
573			} else {
574				sockFlags = darwinDockerSockFlags(darwinDockerBindSourcePath(sockPath))
575			}
576		case "windows":
577			// Docker Desktop (Linux containers mode): bind-mount the engine socket and match Linux
578			// behavior by adding --group-add for the socket's GID when we can probe it from a disposable container.
579			sockFlags = dockerEngineSockFlagsWindows(h)
580		}
581	
582		cmd := dockerStartCommand(dockerStartOpts{
583			ContainerName: cname,
584			InstanceName:  instanceName,
585			RegToken:      regToken,
586			RepoURL:       repoURL,
587			Labels:        labels,
588			SockMount:     sockFlags,
589			Image:         RunnerDockerImage,
590			NetworkMode:   rc.EffectiveDockerNetworkMode(h.OS),
591			CapAdds:       rc.DockerCapAdd,
592			RunnerGroup:   rc.Group,
593			Ephemeral:     rc.Ephemeral,
594			PreSetup:      rc.DockerPreSetup,
595		})
596	
597		out, err := dockerRun(h, cmd)
598		if err != nil {
599			return fmt.Errorf("starting Docker container: %w", err)
600		}
601	
602		containerID := strings.TrimSpace(out)
603		if len(containerID) > 12 {
604			containerID = containerID[:12]
605		}
606		fmt.Fprintf(m.out(), "  %s: started (container %s)\n", instanceName, containerID)
607		return nil
608	}
609	
610	func (m *Manager) stopDocker(h *host.Host, instanceName string) error {
611		cname := containerName(instanceName)
612	
613		var inspectCmd string
614		if h.OS == "windows" {
615			inspectCmd = fmt.Sprintf(`docker inspect -f "{{.State.Running}}" %s 2>$null`, cname)
616		} else {
617			inspectCmd = fmt.Sprintf("docker inspect -f '{{.State.Running}}' %s 2>/dev/null", cname)
618		}
619		running, _ := dockerRun(h, inspectCmd)
620		if strings.TrimSpace(running) != "true" {
621			fmt.Fprintf(m.out(), "  %s: not running\n", instanceName)
622			return nil
623		}
624	
625		if _, err := dockerRun(h, fmt.Sprintf("docker stop -t 30 %s", cname)); err != nil {
626			return fmt.Errorf("stopping container: %w", err)
627		}
628	
629		fmt.Fprintf(m.out(), "  %s: stopped\n", instanceName)
630		return nil
631	}
632	
633	func (m *Manager) removeDocker(h *host.Host, instanceName string) error {
634		cname := containerName(instanceName)
635	
636		_ = m.stopDocker(h, instanceName)
637	
638		var rmCmd string
639		if h.OS == "windows" {
640			rmCmd = fmt.Sprintf("docker rm -f %s 2>$null", cname)
641		} else {
642			rmCmd = fmt.Sprintf("docker rm -f %s 2>/dev/null || true", cname)
643		}
644		if _, err := dockerRun(h, rmCmd); err != nil {
645			return fmt.Errorf("removing container: %w", err)
646		}
647	
648		fmt.Fprintf(m.out(), "  %s: removed\n", instanceName)
649		return nil
650	}
651	
652	func (m *Manager) statusDocker(h *host.Host, instanceName string) string {
653		cname := containerName(instanceName)
654	
655		var inspectCmd string
656		if h.OS == "windows" {
657			inspectCmd = fmt.Sprintf(`docker inspect -f "{{.State.Status}}" %s 2>$null`, cname)
658		} else {
659			inspectCmd = fmt.Sprintf("docker inspect -f '{{.State.Status}}' %s 2>/dev/null", cname)
660		}
661		out, err := dockerRun(h, inspectCmd)
662		if err != nil {
663			return "not installed"
664		}
665	
666		status := strings.TrimSpace(out)
667		switch status {
668		case "running":
669			return "running"
670		case "exited", "dead", "created":
671			return "stopped"
672		default:
673			return status
674		}
675	}
676	
677	func (m *Manager) logsDocker(h *host.Host, instanceName string) (string, error) {
678		cname := containerName(instanceName)
679		cmd := fmt.Sprintf("docker logs --tail 50 %s 2>&1", cname)
680		return dockerRun(h, cmd)
681	}
